// Apply Dynamic Pricing Rules
// Based on demand forecast, inventory levels, and competitor pricing with margin protection

const items = $input.all();
const processedItems = [];

for (const item of items) {
  const data = item.json;

  // Extract relevant data
  const basePrice = data.basePrice || data.price || 0;
  const demandForecast = data.demandForecast || data.forecast || 'medium';
  const inventoryLevel = data.inventoryLevel || data.inventory || 0;
  const competitorPrice = data.competitorPrice || basePrice;
  const minMargin = data.minMargin || 0.15; // 15% minimum margin
  const cost = data.cost || basePrice * 0.6; // Assume 40% margin if cost not provided

  let finalPrice = basePrice;
  let priceAdjustment = 0;
  let adjustmentReason = [];

  // Rule 1: Demand-based pricing
  if (demandForecast === 'high' || demandForecast > 0.7) {
    priceAdjustment += basePrice * 0.10; // Increase by 10%
    adjustmentReason.push('High demand forecast');
  } else if (demandForecast === 'low' || demandForecast < 0.3) {
    priceAdjustment -= basePrice * 0.08; // Decrease by 8%
    adjustmentReason.push('Low demand forecast');
  }

  // Rule 2: Inventory-based pricing
  if (inventoryLevel < 10) {
    priceAdjustment += basePrice * 0.05; // Increase by 5% for low stock
    adjustmentReason.push('Low inventory');
  } else if (inventoryLevel > 100) {
    priceAdjustment -= basePrice * 0.10; // Decrease by 10% for overstock
    adjustmentReason.push('Overstock clearance');
  }

  // Rule 3: Competitor pricing adjustment
  if (competitorPrice < basePrice * 0.95) {
    const competitivePrice = competitorPrice * 0.98; // Price slightly below competitor
    priceAdjustment = competitivePrice - basePrice;
    adjustmentReason.push('Competitive pricing match');
  }

  // Calculate proposed price
  finalPrice = basePrice + priceAdjustment;

  // Rule 4: Margin protection - ensure minimum margin is maintained
  const minPrice = cost / (1 - minMargin);
  if (finalPrice < minPrice) {
    finalPrice = minPrice;
    adjustmentReason.push('Margin protection applied');
  }

  // Calculate final metrics
  const margin = ((finalPrice - cost) / finalPrice) * 100;
  const priceChangePercent = ((finalPrice - basePrice) / basePrice) * 100;

  processedItems.push({
    json: {
      ...data,
      basePrice: basePrice,
      finalPrice: Math.round(finalPrice * 100) / 100,
      priceAdjustment: Math.round(priceAdjustment * 100) / 100,
      priceChangePercent: Math.round(priceChangePercent * 100) / 100,
      margin: Math.round(margin * 100) / 100,
      adjustmentReason: adjustmentReason.join(', '),
      pricingTimestamp: new Date().toISOString()
    }
  });
}

return processedItems;

// Apply Promotion Rules based on customer segments, product categories, seasonal campaigns, and inventory clearance

const items = $input.all();
const promotionalItems = [];

for (const item of items) {
  const data = item.json;

  // Initialize promotion fields
  let promotionType = 'none';
  let discountPercentage = 0;
  let promotionReason = [];

  // Extract relevant data
  const customerSegment = data.customerSegment || data.customer_segment || 'standard';
  const productCategory = data.productCategory || data.category || 'general';
  const inventoryLevel = data.inventoryLevel || data.stock_level || 100;
  const productPrice = data.price || data.product_price || 0;
  const purchaseHistory = data.purchaseHistory || data.total_purchases || 0;

  // Get current date for seasonal campaigns
  const currentDate = new Date();
  const currentMonth = currentDate.getMonth() + 1; // 1-12
  const currentDay = currentDate.getDate();

  // Rule 1: Customer Segment-based Promotions
  if (customerSegment === 'vip' || customerSegment === 'premium') {
    discountPercentage = Math.max(discountPercentage, 15);
    promotionType = 'vip_discount';
    promotionReason.push('VIP Customer Loyalty Discount');
  } else if (customerSegment === 'loyal' && purchaseHistory > 5) {
    discountPercentage = Math.max(discountPercentage, 10);
    promotionType = 'loyalty_discount';
    promotionReason.push('Loyal Customer Appreciation');
  } else if (customerSegment === 'new' || purchaseHistory === 0) {
    discountPercentage = Math.max(discountPercentage, 20);
    promotionType = 'new_customer_welcome';
    promotionReason.push('New Customer Welcome Offer');
  }

  // Rule 2: Product Category Promotions
  if (productCategory === 'electronics') {
    discountPercentage = Math.max(discountPercentage, 12);
    promotionType = 'category_promo';
    promotionReason.push('Electronics Flash Sale');
  } else if (productCategory === 'fashion' || productCategory === 'clothing') {
    discountPercentage = Math.max(discountPercentage, 25);
    promotionType = 'category_promo';
    promotionReason.push('Fashion Week Special');
  } else if (productCategory === 'home' || productCategory === 'furniture') {
    discountPercentage = Math.max(discountPercentage, 18);
    promotionType = 'category_promo';
    promotionReason.push('Home Makeover Sale');
  }

  // Rule 3: Seasonal Campaign Promotions
  // Black Friday (November)
  if (currentMonth === 11 && currentDay >= 20 && currentDay <= 30) {
    discountPercentage = Math.max(discountPercentage, 40);
    promotionType = 'seasonal_campaign';
    promotionReason.push('Black Friday Mega Sale');
  }
  // Holiday Season (December)
  else if (currentMonth === 12) {
    discountPercentage = Math.max(discountPercentage, 30);
    promotionType = 'seasonal_campaign';
    promotionReason.push('Holiday Season Special');
  }
  // Summer Sale (June-August)
  else if (currentMonth >= 6 && currentMonth <= 8) {
    discountPercentage = Math.max(discountPercentage, 20);
    promotionType = 'seasonal_campaign';
    promotionReason.push('Summer Clearance Sale');
  }
  // Spring Sale (March-May)
  else if (currentMonth >= 3 && currentMonth <= 5) {
    discountPercentage = Math.max(discountPercentage, 15);
    promotionType = 'seasonal_campaign';
    promotionReason.push('Spring Refresh Sale');
  }

  // Rule 4: Inventory Clearance (High Priority)
  if (inventoryLevel > 200) {
    discountPercentage = Math.max(discountPercentage, 35);
    promotionType = 'clearance';
    promotionReason.push('Overstock Clearance - Limited Time');
  } else if (inventoryLevel > 100) {
    discountPercentage = Math.max(discountPercentage, 25);
    promotionType = 'clearance';
    promotionReason.push('Inventory Reduction Sale');
  } else if (inventoryLevel < 10) {
    // Low stock - no discount, create urgency
    promotionType = 'urgency';
    promotionReason.push('Low Stock Alert - Order Now');
  }

  // Calculate final price
  const discountAmount = (productPrice * discountPercentage) / 100;
  const finalPrice = productPrice - discountAmount;

  // Build promotional item
  promotionalItems.push({
    json: {
      ...data,
      promotion: {
        applied: discountPercentage > 0,
        type: promotionType,
        discountPercentage: discountPercentage,
        discountAmount: Math.round(discountAmount * 100) / 100,
        originalPrice: productPrice,
        finalPrice: Math.round(finalPrice * 100) / 100,
        reasons: promotionReason,
        campaignDate: currentDate.toISOString(),
        urgency: inventoryLevel < 10 ? 'high' : inventoryLevel < 50 ? 'medium' : 'low'
      },
      promotionApplied: true,
      processedAt: new Date().toISOString()
    }
  });
}

return promotionalItems;

// Calculate replenishment quantities based on demand forecast, lead times, safety stock levels, and supplier constraints

const items = $input.all();
const replenishmentResults = [];

for (const item of items) {
  const data = item.json;

  // Extract relevant data
  const currentStock = data.currentStock || 0;
  const demandForecast = data.demandForecast || 0;
  const leadTimeDays = data.leadTimeDays || 7;
  const safetyStockLevel = data.safetyStockLevel || 0;
  const supplierMinOrder = data.supplierMinOrder || 1;
  const supplierMaxOrder = data.supplierMaxOrder || 10000;
  const productId = data.productId || data.id;

  // Calculate daily demand rate
  const dailyDemand = demandForecast / 30; // Assuming monthly forecast

  // Calculate lead time demand
  const leadTimeDemand = dailyDemand * leadTimeDays;

  // Calculate reorder point (lead time demand + safety stock)
  const reorderPoint = leadTimeDemand + safetyStockLevel;

  // Calculate optimal order quantity
  let orderQuantity = 0;

  if (currentStock <= reorderPoint) {
    // Calculate quantity needed to reach target stock level
    const targetStock = reorderPoint + (dailyDemand * 30); // 30 days of stock
    orderQuantity = Math.max(0, targetStock - currentStock);

    // Apply supplier constraints
    orderQuantity = Math.max(orderQuantity, supplierMinOrder);
    orderQuantity = Math.min(orderQuantity, supplierMaxOrder);

    // Round up to nearest whole number
    orderQuantity = Math.ceil(orderQuantity);
  }

  // Calculate days until stockout
  const daysUntilStockout = currentStock > 0 ? currentStock / dailyDemand : 0;

  // Determine urgency level
  let urgency = 'low';
  if (currentStock <= safetyStockLevel) {
    urgency = 'critical';
  } else if (currentStock <= reorderPoint) {
    urgency = 'high';
  } else if (daysUntilStockout <= leadTimeDays * 2) {
    urgency = 'medium';
  }

  replenishmentResults.push({
    json: {
      ...data,
      replenishment: {
        productId,
        currentStock,
        demandForecast,
        dailyDemand: Math.round(dailyDemand * 100) / 100,
        reorderPoint: Math.ceil(reorderPoint),
        safetyStockLevel,
        orderQuantity,
        leadTimeDays,
        daysUntilStockout: Math.round(daysUntilStockout * 10) / 10,
        urgency,
        shouldReorder: orderQuantity > 0,
        supplierConstraints: {
          minOrder: supplierMinOrder,
          maxOrder: supplierMaxOrder
        },
        calculatedAt: new Date().toISOString()
      }
    }
  });
}

return replenishmentResults;

